class t{constructor(t={}){this.options={container:"#vr-container",...t},this.session=null,this.isVRSupported=!1,this.init()}async init(){this.checkVRSupport(),this.setupVRButton()}async checkVRSupport(){"xr"in navigator&&(this.isVRSupported=await navigator.xr.isSessionSupported("immersive-vr"))}setupVRButton(){document.querySelectorAll("[data-vr-enter]").forEach(t=>{this.isVRSupported?t.addEventListener("click",()=>this.enterVR()):t.style.display="none"})}async enterVR(){}}export{t as VRSystem};
